import { useState, useRef, useEffect, useCallback } from 'react';
import '../styles/Certificates.css';

const IconPdf = () => (
  <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
    <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z" />
    <polyline points="14 2 14 8 20 8" />
    <line x1="12" y1="18" x2="12" y2="12" />
    <line x1="9" y1="15" x2="15" y2="15" />
  </svg>
);

const IconCarousel = () => (
  <svg width="13" height="13" fill="none" stroke="currentColor" strokeWidth="2.2" viewBox="0 0 24 24">
    <rect x="3" y="3" width="7" height="18" rx="1" />
    <rect x="14" y="3" width="7" height="18" rx="1" />
  </svg>
);

const IconGrid = () => (
  <svg width="13" height="13" fill="none" stroke="currentColor" strokeWidth="2.2" viewBox="0 0 24 24">
    <rect x="3" y="3" width="7" height="7" rx="1" />
    <rect x="14" y="3" width="7" height="7" rx="1" />
    <rect x="3" y="14" width="7" height="7" rx="1" />
    <rect x="14" y="14" width="7" height="7" rx="1" />
  </svg>
);

const IconChevLeft = () => (
  <svg width="16" height="16" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24">
    <path d="M15 18l-6-6 6-6" />
  </svg>
);

const IconChevRight = () => (
  <svg width="16" height="16" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24">
    <path d="M9 18l6-6-6-6" />
  </svg>
);

const certData = [
  {
    icon: '🏅',
    org: 'Meta · Coursera',
    name: 'Frontend Developer Professional Certificate',
    date: 'Issued: March 2024',
    pdf: 'cert1.pdf',
  },
  {
    icon: '☁️',
    org: 'Google · Coursera',
    name: 'Google IT Support Specialist',
    date: 'Issued: January 2024',
    pdf: 'cert2.pdf',
  },
  {
    icon: '🔥',
    org: 'freeCodeCamp',
    name: 'Responsive Web Design Certification',
    date: 'Issued: September 2023',
    pdf: 'cert3.pdf',
  },
  {
    icon: '⚡',
    org: 'Udemy',
    name: 'The Complete JavaScript Course 2024',
    date: 'Issued: June 2023',
    pdf: 'cert4.pdf',
  },
  {
    icon: '🎯',
    org: 'Figma · UI/UX Design',
    name: 'UI/UX Design Fundamentals',
    date: 'Issued: December 2023',
    pdf: 'cert5.pdf',
  },
  {
    icon: '🐍',
    org: 'Cisco Networking Academy',
    name: 'Python Essentials Certification',
    date: 'Issued: April 2024',
    pdf: 'cert6.pdf',
  },
];

function CertCard({ cert, onOpen, gridMode }) {
  return (
    <div className="cert-card" onClick={() => onOpen(cert)}>
      <div className="cert-img-area">
        <div className="cert-badge-icon">{cert.icon}</div>
      </div>
      <div className="cert-body">
        <div className="cert-org">{cert.org}</div>
        <div className="cert-name">{cert.name}</div>
        <div className="cert-date">{cert.date}</div>
        <a
          href={cert.pdf}
          className="cert-pdf-link"
          target="_blank"
          rel="noreferrer"
          onClick={(e) => e.stopPropagation()}
        >
          <IconPdf /> View Certificate (PDF)
        </a>
      </div>
    </div>
  );
}

export default function Certificates() {
  const [view, setView] = useState('carousel');
  const [idx, setIdx] = useState(0);
  const [modal, setModal] = useState(null);
  const trackRef = useRef(null);
  const touchStartX = useRef(0);

  const getItemsPerView = useCallback(() => {
    if (window.innerWidth <= 768) return 1;
    if (window.innerWidth <= 1024) return 2;
    return 3;
  }, []);

  const totalSlides = Math.ceil(certData.length / getItemsPerView());

  const goTo = useCallback(
    (i) => {
      const perView = getItemsPerView();
      const clampedIdx = Math.max(0, Math.min(i, Math.ceil(certData.length / perView) - 1));
      setIdx(clampedIdx);

      const track = trackRef.current;
      if (!track) return;
      const card = track.querySelector('.cert-card');
      if (!card) return;
      const cardWidth = card.offsetWidth + 16;
      track.style.transform = `translateX(-${clampedIdx * perView * cardWidth}px)`;
    },
    [getItemsPerView]
  );

  useEffect(() => {
    const handleResize = () => goTo(0);
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, [goTo]);

  const prev = () => {
    const perView = getItemsPerView();
    const total = Math.ceil(certData.length / perView);
    goTo(idx <= 0 ? total - 1 : idx - 1);
  };

  const next = () => {
    const perView = getItemsPerView();
    const total = Math.ceil(certData.length / perView);
    goTo(idx >= total - 1 ? 0 : idx + 1);
  };

  const onTouchStart = (e) => { touchStartX.current = e.touches[0].clientX; };
  const onTouchEnd = (e) => {
    const diff = touchStartX.current - e.changedTouches[0].clientX;
    if (Math.abs(diff) > 40) diff > 0 ? next() : prev();
  };

  const openModal = (cert) => {
    setModal(cert);
    document.body.style.overflow = 'hidden';
  };

  const closeModal = () => {
    setModal(null);
    document.body.style.overflow = '';
  };

  useEffect(() => {
    const handleKey = (e) => { if (e.key === 'Escape') closeModal(); };
    document.addEventListener('keydown', handleKey);
    return () => document.removeEventListener('keydown', handleKey);
  }, []);

  const perView = getItemsPerView();
  const dots = Math.ceil(certData.length / perView);

  return (
    <section id="certificates" className="certificates-section">
      <div className="certificates-inner">

        {/* Controls */}
        <div className="cert-controls reveal">
          <div className="section-header" style={{ marginBottom: 0 }}>
            <div className="section-tag">Achievements</div>
            <h2 className="section-title">
              Certificates &<br /><span className="accent">Credentials</span>
            </h2>
          </div>
          <div className="view-toggle">
            <button
              className={`toggle-btn${view === 'carousel' ? ' active' : ''}`}
              onClick={() => setView('carousel')}
            >
              <IconCarousel /> Carousel
            </button>
            <button
              className={`toggle-btn${view === 'grid' ? ' active' : ''}`}
              onClick={() => setView('grid')}
            >
              <IconGrid /> Grid
            </button>
          </div>
        </div>

        {/* CAROUSEL VIEW */}
        {view === 'carousel' && (
          <div className="carousel-wrap">
            <div
              className="carousel-track-outer"
              onTouchStart={onTouchStart}
              onTouchEnd={onTouchEnd}
            >
              <div className="carousel-track" ref={trackRef}>
                {certData.map((cert, i) => (
                  <CertCard cert={cert} key={i} onOpen={openModal} />
                ))}
              </div>
            </div>

            <div className="carousel-nav">
              <button className="carousel-btn" onClick={prev} aria-label="Previous">
                <IconChevLeft />
              </button>
              <div className="carousel-dots">
                {Array.from({ length: dots }).map((_, i) => (
                  <button
                    key={i}
                    className={`carousel-dot${i === idx ? ' active' : ''}`}
                    onClick={() => goTo(i)}
                    aria-label={`Go to slide ${i + 1}`}
                  />
                ))}
              </div>
              <button className="carousel-btn" onClick={next} aria-label="Next">
                <IconChevRight />
              </button>
            </div>
          </div>
        )}

        {/* GRID VIEW */}
        {view === 'grid' && (
          <div className="cert-grid-view active">
            {certData.map((cert, i) => (
              <CertCard cert={cert} key={i} onOpen={openModal} gridMode />
            ))}
          </div>
        )}

      </div>

      {/* MODAL */}
      {modal && (
        <div
          className={`cert-modal${modal ? ' open' : ''}`}
          onClick={(e) => { if (e.target.classList.contains('cert-modal')) closeModal(); }}
        >
          <div className="modal-inner">
            <button className="modal-close" onClick={closeModal}>✕</button>
            <div className="modal-icon">{modal.icon}</div>
            <div className="modal-org">{modal.org}</div>
            <div className="modal-name">{modal.name}</div>
            <div className="modal-date">{modal.date}</div>
            <p className="modal-desc">
              This certificate represents the successful completion of a comprehensive
              course covering both theoretical concepts and practical hands-on projects.
              Skills validated through this credential are actively applied in real-world projects.
            </p>
            <br />
            <a
              href={modal.pdf}
              className="cert-pdf-link"
              target="_blank"
              rel="noreferrer"
              style={{ marginTop: '1rem' }}
            >
              <IconPdf /> View Full Certificate (PDF)
            </a>
          </div>
        </div>
      )}
    </section>
  );
}
